const fs = require('fs');
const path = require('path');

// 解析scriptfile
let scriptObj = {}
let scriptsStr = fs.readFileSync('./ScriptFile.tab').toString();
scriptsStr.split('\n').forEach(line => {
    let tmps = line.split('\t');
    if (tmps.length  < 2) {
        return
    }
    let id = parseInt(tmps[0]);
    if (id <= 0) {
        return
    }
    scriptObj[tmps[0]] = tmps[1]
})

