// 如果想保存结果到文件，请取消注释以下行：
// fs.writeFileSync('.txt', res, 'utf8');
function replaceConNumber(ablPath, scriptID, newNumber) {
    // 拼出 con 的前缀，例如： x123_var_Buf1 =
    const prefix = `x${scriptID}_var_Buf1 =`;

    // 读取文件内容
    let text = fs.readFileSync(ablPath, 'utf8');

    // 构造正则：匹配类似 “x123_var_Buf1 = 任意数字”
    const reg = new RegExp(`${prefix}\\s*\\d+`);

    // 新文本
    const newCon = `${prefix} ${newNumber}`;

    // 判断是否存在
    if (!reg.test(text)) {
        console.error(`⚠️ 文件中找不到 ${prefix} 对应的行`);
        return false;
    }

    // 替换
    text = text.replace(reg, newCon);

    // 写回文件
    fs.writeFileSync(ablPath, text, 'utf8');

    return true;
}